using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var searchApiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

// --- Build the chat client with tool support ---
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Tool instances ---
var notepad = new Notepad();
var webSearch = new WebSearchTool(searchApiKey);

// --- Register tools ---
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// --- Get research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Agent system prompt ---
var systemPrompt = """
    You are a research agent. Your goal is to thoroughly research the given topic
    by searching the web multiple times with different queries, taking notes on
    important findings, and then producing a clear summary.

    Workflow:
    1. Break the topic into 2-3 search queries that cover different aspects.
    2. For each query, call the SearchWeb tool.
    3. After each search, call AddNote to record key findings.
    4. After all searches, call GetNotes to review everything you've collected.
    5. Produce a final, well-structured summary of your research.

    Be thorough but concise in your final summary.
    """;

// --- Run the agent loop ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic: {topic}")
};

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══ Research Summary ═══\n");
Console.WriteLine(response.Text);
Console.WriteLine($"\n═══ Notes Collected ({notepad.Notes.Count}) ═══");
foreach (var (i, note) in notepad.Notes.Select((n, i) => (i, n)))
{
    Console.WriteLine($"\n--- Note {i + 1} ---");
    Console.WriteLine(note);
}

// --- Tool Definitions ---

/// <summary>Provides web search capabilities using Brave Search API (or simulated results).</summary>
sealed class WebSearchTool(string apiKey)
{
    private static readonly HttpClient Http = new();

    [Description("Searches the web for the given query and returns a summary of results.")]
    public async Task<string> SearchWeb([Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        if (!string.IsNullOrEmpty(apiKey))
        {
            return await SearchBrave(query);
        }

        return await SearchFallback(query);
    }

    private async Task<string> SearchBrave(string query)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var results = doc.RootElement.GetProperty("web").GetProperty("results");

        var summaries = new List<string>();
        foreach (var result in results.EnumerateArray().Take(5))
        {
            var title = result.GetProperty("title").GetString();
            var description = result.TryGetProperty("description", out var desc)
                ? desc.GetString() : "No description";
            var url = result.GetProperty("url").GetString();
            summaries.Add($"- [{title}]({url}): {description}");
        }

        return $"Search results for \"{query}\":\n{string.Join("\n", summaries)}";
    }

    private static async Task<string> SearchFallback(string query)
    {
        // Use DuckDuckGo instant answer API as a free fallback
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        try
        {
            var response = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
                results.Add($"Summary: {abstractText}");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                        results.Add($"- {t}");
                }
            }

            return results.Count > 0
                ? $"Search results for \"{query}\":\n{string.Join("\n", results)}"
                : $"Search results for \"{query}\": No detailed results found. The topic may require more specific queries.";
        }
        catch
        {
            return $"Search results for \"{query}\": Search unavailable. Please try a different query.";
        }
    }
}

/// <summary>A simple note-taking tool that stores research notes in memory.</summary>
sealed class Notepad
{
    public List<string> Notes { get; } = [];

    [Description("Adds a research note. Use this to record important findings from searches.")]
    public string AddNote([Description("The note content to save")] string content)
    {
        Notes.Add(content);
        Console.WriteLine($"  📝 Note added ({Notes.Count} total)");
        return $"Note saved. You now have {Notes.Count} note(s).";
    }

    [Description("Retrieves all notes taken so far. Use this to review findings before summarizing.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes taken yet.";

        var combined = string.Join("\n\n", Notes.Select((n, i) => $"[Note {i + 1}]: {n}"));
        Console.WriteLine($"  📋 Retrieved {Notes.Count} note(s)");
        return combined;
    }
}

